import { defineConfig } from '@tanstack/start/config'
import tailwindcss from '@tailwindcss/vite'

export default defineConfig({
  tsr: {
    target: 'react',
    autoCodeSplitting: true,
    __enableAPIRoutesGeneration: true,
  },
  vite: {
    plugins: [tailwindcss()],
  },
  server: {
    preset: 'node-server',
  },
})

import Database from 'better-sqlite3'
import path from 'path'

const DB_PATH = path.join(process.cwd(), 'counter.db')

let db: Database.Database | null = null

function getDb(): Database.Database {
  if (!db) {
    db = new Database(DB_PATH)
    db.pragma('journal_mode = WAL')
    db.exec(`
      CREATE TABLE IF NOT EXISTS counter (
        id INTEGER PRIMARY KEY CHECK (id = 1),
        count INTEGER NOT NULL DEFAULT 0
      )
    `)
    db.exec(`
      INSERT OR IGNORE INTO counter (id, count) VALUES (1, 0)
    `)
  }
  return db
}

export function getCount(): number {
  const row = getDb().prepare('SELECT count FROM counter WHERE id = 1').get() as { count: number } | undefined
  return row?.count ?? 0
}

export function incrementCount(): number {
  const result = getDb().prepare('UPDATE counter SET count = count + 1 WHERE id = 1 RETURNING count').get() as { count: number }
  return result.count
}

import { createServerFn } from '@tanstack/react-start'
import { getCount, incrementCount } from '../db'

export const getCounter = createServerFn({ method: 'GET' }).handler(
  async () => {
    return { count: getCount() }
  }
)

export const incrementCounter = createServerFn({ method: 'POST' }).handler(
  async () => {
    return { count: incrementCount() }
  }
)

import ReactDOM from 'react-dom/client'
import { StartClient } from '@tanstack/react-start'
import { createRouter } from './router'

const router = createRouter()

const rootElement = document.getElementById('app')!

if (!rootElement.innerHTML) {
  const root = ReactDOM.createRoot(rootElement)
  root.render(<StartClient router={router} />)
}

import { createStartHandler, defaultStreamHandler } from '@tanstack/react-start/server'
import { createRouter } from './router'

export default createStartHandler({
  router: createRouter,
  createStream: defaultStreamHandler,
})

import { createRouter as createTanStackRouter } from '@tanstack/react-router'
import { routeTree } from './routeTree.gen'

export function createRouter() {
  const router = createTanStackRouter({
    routeTree,
    scrollRestoration: true,
    defaultPreload: 'intent',
  })

  return router
}

declare module '@tanstack/react-router' {
  interface Register {
    router: ReturnType<typeof createRouter>
  }
}

import { Outlet, createRootRoute } from '@tanstack/react-router'

import '../styles.css'

export const Route = createRootRoute({
  component: RootComponent,
})

function RootComponent() {
  return (
    <div>
      <Outlet />
    </div>
  )
}

import { createFileRoute } from '@tanstack/react-router'
import { getCounter, incrementCounter } from '../server/counter'

export const Route = createFileRoute('/')({
  component: Home,
  loader: async () => {
    const data = await getCounter()
    return { count: data.count }
  },
})

function Home() {
  const { count } = Route.useLoaderData()
  const [currentCount, setCurrentCount] = React.useState(count)
  const [isPending, setIsPending] = React.useState(false)

  const handleIncrement = async () => {
    setIsPending(true)
    try {
      const result = await incrementCounter()
      setCurrentCount(result.count)
    } finally {
      setIsPending(false)
    }
  }

  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1>Counter App</h1>
      <p data-testid="count" style={{ fontSize: '2rem', margin: '1rem 0' }}>
        Count: {currentCount}
      </p>
      <button onClick={handleIncrement} disabled={isPending} style={{ fontSize: '1rem', padding: '0.5rem 1rem' }}>
        {isPending ? 'Incrementing...' : 'Increment'}
      </button>
    </div>
  )
}

