import {
  createStartHandler,
  defaultStreamHandler,
} from '@tanstack/react-start/server'
import { createRouter } from './router'
import { getCount, incrementCount } from './db'

const startHandler = createStartHandler({
  router: createRouter,
  createStream: defaultStreamHandler,
})

async function handler(request: Request): Promise<Response> {
  const url = new URL(request.url)

  // Handle API routes
  if (url.pathname === '/api/counter' && request.method === 'GET') {
    const count = getCount()
    return new Response(JSON.stringify({ count }), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  if (url.pathname === '/api/counter/increment' && request.method === 'POST') {
    const count = incrementCount()
    return new Response(JSON.stringify({ count }), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  // Delegate to TanStack Start SSR handler
  return startHandler(request)
}

export default {
  fetch: handler,
}

